local G = DYCLegendary local require = G.DYCModRequire local Spell = require( "dyc_spell" ) local DYCSpawnFX = require( "dyc_spawnfx" ) local CommonFns = require( "dyc_commonfns" ) local IsAliveOrNoHealth = CommonFns.IsAliveOrNoHealth local CanHit = CommonFns.CanHit local Ignite = CommonFns.Ignite local fxs = { "dyc_fx_firepuff1" , "dyc_fx_firepuff2" , "dyc_fx_firepuff3" ,} local function RandomFX() return fxs[math.random(#fxs)] end local fxs2 = { "dyc_fx_sparks_l" , "dyc_fx_sparks_m" , "dyc_fx_sparks_s" ,} local function RandomFX2() return fxs2[math.random(#fxs2)] end local fxs3 = { "dyc_fx_coldfirepuff1" , "dyc_fx_coldfirepuff2" , "dyc_fx_coldfirepuff3" ,} local function RandomFX3() return fxs3[math.random(#fxs3)] end local fxs4 = { "dyc_fx_sparks_blue_l" , "dyc_fx_sparks_blue_m" , "dyc_fx_sparks_blue_s" ,} local function RandomFX4() return fxs4[math.random(#fxs4)] end local function TableContains(_table, _thing) for k, v in pairs(_table) do if v == _thing then return true end end return false end local function Strike(spell, p, dmgGroup) local damage = spell.damage local caster = spell.caster local fx = spell.flameColor == "blue" and SpawnPrefab(RandomFX3()) or SpawnPrefab(RandomFX()) fx.Transform:SetPosition(p.x, p.y, p.z) fx.Transform:SetScale(0.7, 0.7, 0.7) local fx2 = spell.flameColor == "blue" and SpawnPrefab(RandomFX4()) or SpawnPrefab(RandomFX2()) fx2.Transform:SetPosition(p.x, p.y, p.z) local randomScale = math.random() * 0.2 + 0.7 fx2.Transform:SetScale(randomScale, randomScale, randomScale) local ents = TheSim:FindEntities(p.x, p.y, p.z, 1.7) for k, v in pairs(ents) do if CanHit(v, caster) and not TableContains(dmgGroup, v) then table.insert(dmgGroup, v) if IsAliveOrNoHealth(v) and spell.damageType == "fire" then Ignite(v, caster, spell.flameColor) end if IsAliveOrNoHealth(v) and v.components.combat then v.isNonAttDmg = true v.components.combat:GetAttacked(caster, damage, nil) v.isNonAttDmg = nil end if IsAliveOrNoHealth(v) and spell.damageType == "ice" then if v.components.freezable then v.components.freezable:AddColdness(spell.coldness or 0x1) v.components.freezable:SpawnShatterFX() end if v.components.burnable then if v.components.burnable:IsBurning() then v.components.burnable:Extinguish() elseif v.components.burnable.IsSmoldering and v.components.burnable:IsSmoldering() then v.components.burnable:SmotherSmolder() end end end end end end local function onSetData(spell, data) data = data or {} spell.caster = data.caster spell.damage = data and data.damage or 0xa spell.range = data and data.range or 0x6 spell.interval = data and data.interval or 0.6 spell.offset = data and data.offset or 0.5 spell.speed = data and data.speed or 0xf spell.number = data and data.number or 0x1 spell.angle = data and data.angle and data.angle * math.pi / 0xb4 or math.pi / 0x9 spell.damageType = data and data.damageType or "fire" spell.flameColor = data and data.flameColor or "red" spell.coldness = data and data.coldness or 0x1 end local name = "firefissure" local SpellClass = Class(Spell, function(self, data) Spell._ctor(self, {name = name,}) local spell = self spell.onSetData = onSetData spell:SetData(data) spell.onCast = function(spell, target, p) local pos = spell.caster:GetPosition() local facingAngle = math.rad(spell.caster.Transform:GetRotation() + 0x5a) p = p or pos + Vector3(math.sin(facingAngle) * 0x3, 0x0, math.cos(facingAngle) * 0x3) local timer, dist = 0x0, 0x0 local p0 = spell.caster:GetPosition() local angles = {} local a = math.atan2(p.z - p0.z, p.x - p0.x) if spell.caster:GetPosition():Dist(p) < 0.1 then a = spell.caster.Transform:GetRotation() end p0 = Vector3(p0.x + spell.offset * math.cos(a), 0x0, p0.z + spell.offset * math.sin(a)) for i = 0x1, spell.number do table.insert(angles, a - (spell.number - 0x1) * spell.angle / 0x2 + (i - 0x1) * spell.angle) end local dmgGroup = {} local task = nil task = spell:StartTask(function() timer = timer + FRAMES dist = dist + FRAMES * spell.speed local distance = timer * spell.speed if distance > spell.range then spell:StopTask(task) else if dist > spell.interval then dist = 0x0 for k, v in pairs(angles) do local newp = Vector3(p0.x + distance * math.cos(v), 0x0, p0.z + distance * math.sin(v)) Strike(spell, newp, dmgGroup) end end end end) end end) SpellClass.name = name return SpellClass 